def perceive(data):
    out = {}
    for line in str(data).splitlines():
        if ":" not in line:
            continue
        key, _, val = line.partition(":")
        key = key.strip().lower()
        val = val.strip()
        if key == "readiness":
            try:
                out["readiness"] = max(0, min(100, int(val)))
            except (ValueError, TypeError):
                pass
        elif key in ("followup", "follow_up", "followup_scheduled"):
            out["followup_scheduled"] = val.lower() in ("yes", "true", "1", "scheduled", "booked")
    return out
